<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --projected-credibility</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.8</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
